function solve(nums) {
    let maxSum = 0;
    const n = nums.length;

    // Iterate all possible masks for A and B (each bit represents if the element is in A or B)
    // Since n is up to 19, we can't iterate all 3^19 possibilities, but we can optimize
    // Instead, we can iterate all possible splits for A and B, and the rest goes to C

    // Precompute prefix XOR and suffix XOR
    const prefixXOR = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixXOR[i + 1] = prefixXOR[i] ^ nums[i];
    }
    const suffixXOR = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        suffixXOR[i] = suffixXOR[i + 1] ^ nums[i];
    }

    // Iterate all possible non-empty B subarrays (contiguous)
    for (let l = 0; l < n; l++) {
        let andB = ~0; // all bits set to 1
        for (let r = l; r < n; r++) {
            andB &= nums[r];
            // A is [0..l-1], B is [l..r], C is [r+1..n-1]
            const xorA = prefixXOR[l];
            const xorC = suffixXOR[r + 1];
            const currentSum = xorA + andB + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    // Also consider cases where B is empty (all elements in A or C)
    // A is non-empty, C is empty
    for (let l = 1; l <= n; l++) {
        const xorA = prefixXOR[l];
        const andB = 0;
        const xorC = 0;
        const currentSum = xorA + andB + xorC;
        if (currentSum > maxSum) {
            maxSum = currentSum;
        }
    }

    // A is empty, C is non-empty
    for (let r = 0; r < n; r++) {
        const xorA = 0;
        const andB = 0;
        const xorC = suffixXOR[r];
        const currentSum = xorA + andB + xorC;
        if (currentSum > maxSum) {
            maxSum = currentSum;
        }
    }

    // A is empty, B is empty, C is full array
    const xorA = 0;
    const andB = 0;
    const xorC = prefixXOR[n];
    const currentSum = xorA + andB + xorC;
    if (currentSum > maxSum) {
        maxSum = currentSum;
    }

    return maxSum;
}

